mapper.select:
select t1.addtime, t1.paymenttime, t1.invoicetime, t1.endtime, t1.closetime, order_total, total_price, coupon_id, coupon_price, freight_price, pay_way, addr_realname, addr_phone, addr_city, t1.address, ip_address, user_ip, t1.order_id, (case when t1.status=0 and TIMESTAMPDIFF(MINUTE,t1.addtime,NOW()) >=30 then 99 else t1.status end) as status, (case when t1.status=0 and TIMESTAMPDIFF(MINUTE,t1.addtime,NOW()) < 30 then 1800-TIMESTAMPDIFF(SECOND,t1.addtime,NOW()) else 0 end) as surplustimes, t1.user_id, t2.username, t2.phone, express_title, express_name, express_num, buyermessage, buyerrate from shop_order t1 left join sys_app_user t2 on t1.user_id=t2.USER_ID where 1=1
and ( username like concat(concat('%',#{pd.username}),'%') or phone like concat(concat('%',#{pd.username}),'%') )
and (case when t1.status=0 and TIMESTAMPDIFF(MINUTE,t1.addtime,NOW()) >=30 then 99 else t1.status end)=#{pd.status}
and (case when t1.status=0 and TIMESTAMPDIFF(MINUTE,t1.addtime,NOW()) >=30 then 99 else t1.status end) = '99'
and order_id=#{pd.order_id}
and t1.user_id=#{pd.user_id}
and ifnull(LENGTH(t2.INNER_CODE),0) = ifnull(LENGTH(#{pd.INNER_CODE}),0)+32 and t2.INNER_CODE like concat(#{pd.INNER_CODE},'%') and t1.status in (1,2,5,6)
and ifnull(LENGTH(t2.INNER_CODE),0) = ifnull(LENGTH(#{pd.INNER_CODE}),0)+64 and t2.INNER_CODE like concat(#{pd.INNER_CODE},'%') and t1.status in (1,2,5,6)
order by t1.addtime desc

select t1.addtime, t1.paymenttime, t1.invoicetime, t1.endtime, t1.closetime, order_total, total_price, coupon_id, coupon_price,freight_price, pay_way, addr_realname, addr_phone, addr_city, t1.address, ip_address, user_ip, t1.order_id, (case when t1.status=0 and TIMESTAMPDIFF(MINUTE,t1.addtime,NOW()) >=15 then 99 else t1.status end) as status, (case when t1.status=0 and TIMESTAMPDIFF(MINUTE,t1.addtime,NOW()) < 15 then 900-TIMESTAMPDIFF(SECOND,t1.addtime,NOW()) else 0 end) as surplustimes, t1.user_id, t2.username, t2.phone, express_title, express_name, express_num, buyermessage, buyerrate from shop_order t1 left join sys_app_user t2 on t1.user_id=t2.USER_ID where 1=1
and ( username like concat(concat('%',#{username}),'%') or phone like concat(concat('%',#{username}),'%') )
and status=#{status}
and order_id=#{order_id}
and t1.user_id=#{user_id}
order by t1.addtime desc

select
count(1)
from shop_order
where 1=1

and status=#{status}


